package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.Reader;
import java.io.Serializable;
import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.apache.commons.csv.QuoteMode;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testFormat_withNormalValues() {
        String result = csvFormat.format("a", "b", "c");
        // Default delimiter is comma, default quote is double quote, default recordSeparator is CRLF trimmed
        assertEquals("\"a\",\"b\",\"c\"", result);
    }

    @Test
    public void testFormat_withNullValues() {
        String result = csvFormat.format("a", null, "c");
        assertEquals("\"a\",,\"c\"", result);
    }

    @Test
    public void testFormat_withEmptyValues() {
        String result = csvFormat.format("", "", "");
        assertEquals("\"\",\"\",\"\"", result);
    }

    @Test
    public void testFormat_withNoValues() {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    public void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Use reflection to replace CSVPrinter constructor temporarily with a mock that throws IOException on printRecord
        final StringWriter out = new StringWriter();
        CSVFormat formatSpy = spy(csvFormat);

        CSVPrinter printerMock = mock(CSVPrinter.class);
        doThrow(new IOException("mocked IO exception")).when(printerMock).printRecord(any());

        // Use a trick to intercept the CSVPrinter creation inside CSVFormat.format by subclassing CSVFormat
        CSVFormat csvFormatWithMockPrinter = new CSVFormat(formatSpy.getDelimiter(), formatSpy.getQuoteCharacter(),
                formatSpy.getQuoteMode(), formatSpy.getCommentMarker(), formatSpy.getEscapeCharacter(),
                formatSpy.getIgnoreSurroundingSpaces(), formatSpy.getIgnoreEmptyLines(),
                formatSpy.getRecordSeparator(), formatSpy.getNullString(), formatSpy.getHeaderComments(),
                formatSpy.getHeader(), formatSpy.getSkipHeaderRecord(), formatSpy.getAllowMissingColumnNames(),
                formatSpy.getIgnoreHeaderCase()) {
            @Override
            public String format(final Object... values) {
                try {
                    new CSVPrinter(out, this) {
                        @Override
                        public CSVPrinter printRecord(Object... values) throws IOException {
                            throw new IOException("mocked IO exception");
                        }
                    }.printRecord(values);
                    return out.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException ex = assertThrows(IllegalStateException.class, () -> {
            csvFormatWithMockPrinter.format("a", "b");
        });
        assertTrue(ex.getCause() instanceof IOException);
        assertEquals("mocked IO exception", ex.getCause().getMessage());
    }

    @Test
    public void testPrivateIsLineBreak_char() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        method.setAccessible(true);
        // Test line breaks
        assertTrue((Boolean) method.invoke(null, '\r'));
        assertTrue((Boolean) method.invoke(null, '\n'));
        // Test non-line break
        assertFalse((Boolean) method.invoke(null, 'a'));
    }

    @Test
    public void testPrivateIsLineBreak_Character() throws Exception {
        Method method = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        method.setAccessible(true);
        assertTrue((Boolean) method.invoke(null, Character.valueOf('\r')));
        assertTrue((Boolean) method.invoke(null, Character.valueOf('\n')));
        assertFalse((Boolean) method.invoke(null, Character.valueOf('a')));
        assertFalse((Boolean) method.invoke(null, (Character) null));
    }
}
